function onFocusModeChange(mode) {
    var moveControls = document.getElementById('focusMoveControls');
    var localControls = document.getElementById('focusLocalControls');

    if (mode === 'manual') {
        if (moveControls) moveControls.style.display = 'block';
        if (localControls) localControls.style.display = 'none';
        setFocusMode('manual');
        stopFocusTimer();
        var toggle = document.getElementById('focusTimerToggle');
        if (toggle) toggle.checked = false;
    } else if (mode === 'local') {
        if (moveControls) moveControls.style.display = 'none';
        if (localControls) localControls.style.display = 'block';
    } else {
        // 自动
        if (moveControls) moveControls.style.display = 'none';
        if (localControls) localControls.style.display = 'none';
        setFocusMode('auto');
        stopFocusTimer();
        var toggle = document.getElementById('focusTimerToggle');
        if (toggle) toggle.checked = false;
    }
}

// 停止自动对焦
function stopAutoFocus() {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    if (typeof operationLog === 'function') operationLog('用户停止', 'warning');
    apiPost('/api/v1/vision/focus-stop', {}).then(function(r) {
        if (r && r.success) {
            showToast('success', '已停止对焦搜索');
        }
    }).catch(function(e) {
        showToast('error', '停止失败');
    });
    // 恢复按钮状态
    var stopBtn = document.getElementById('btnFocusLocalStop');
    var confirmBtn = document.getElementById('btnFocusTimerConfirm');
    var selectBtn = document.getElementById('btnFocusRegionSelect');
    if (stopBtn) stopBtn.disabled = true;
    if (confirmBtn) { confirmBtn.disabled = true; confirmBtn.style.opacity = '0.5'; }
    if (selectBtn) { selectBtn.style.opacity = '1'; }
    selectBtn.style.opacity = '1';
    stopFocusTimer();
}

// v8.41: 白平衡定时器
function updateWbTimerInput(input) {
    input.value = input.value.replace(/[^0-9]/g, '');
}

function updateFocusTimerInput(input) {
    input.value = input.value.replace(/[^0-9]/g, '');
}

function toggleWbTimer() {
    var toggle = document.getElementById('wbTimerToggle');
    var input = document.getElementById('wbTimerInput');
    if (!toggle || !input) return;
    var minutes = parseInt(input.value) || 0;
    if (minutes <= 0) {
        toggle.checked = false;
        showToast('warning', '请输入大于0的分钟数');
        return;
    }
    if (toggle.checked) {
        var region = localStorage.getItem('region_whitebalance');
        if (!region) {
            toggle.checked = false;
            showToast('warning', '请先框选区域');
            return;
        }
        stopWbTimer();
        wbTimerSeconds = minutes * 60;
        updateWbTimerDisplay();
        wbTimerId = setInterval(function() {
            wbTimerSeconds--;
            updateWbTimerDisplay();
            if (wbTimerSeconds <= 0) {
                clearInterval(wbTimerId);
                wbTimerId = null;
                executeScheduledSearch('whitebalance');
            }
        }, 1000);
        showToast('success', '白平衡定时已启动: ' + minutes + '分钟');
    } else {
        stopWbTimer();
        showToast('info', '白平衡定时已关闭');
    }
}

function toggleFocusTimer() {
    var toggle = document.getElementById('focusTimerToggle');
    var input = document.getElementById('focusTimerInput');
    if (!toggle || !input) return;
    var minutes = parseInt(input.value) || 0;
    if (minutes <= 0) {
        toggle.checked = false;
        showToast('warning', '请输入大于0的分钟数');
        return;
    }
    if (toggle.checked) {
        var region = localStorage.getItem('region_focus');
        if (!region) {
            toggle.checked = false;
            showToast('warning', '请先框选区域');
            return;
        }
        stopFocusTimer();
        focusTimerSeconds = minutes * 60;
        updateFocusTimerDisplay();
        focusTimerId = setInterval(function() {
            focusTimerSeconds--;
            updateFocusTimerDisplay();
            if (focusTimerSeconds <= 0) {
                clearInterval(focusTimerId);
                focusTimerId = null;
                executeScheduledSearch('focus');
            }
        }, 1000);
        showToast('success', '对焦定时已启动: ' + minutes + '分钟');
    } else {
        stopFocusTimer();
        showToast('info', '对焦定时已关闭');
    }
}

function stopWbTimer() {
    if (wbTimerId) { clearInterval(wbTimerId); wbTimerId = null; }
    wbTimerSeconds = 0;
    var display = document.getElementById('wbTimerDisplay');
    if (display) display.textContent = '';
}

function stopFocusTimer() {
    if (focusTimerId) { clearInterval(focusTimerId); focusTimerId = null; }
    focusTimerSeconds = 0;
    var display = document.getElementById('focusTimerDisplay');
    if (display) display.textContent = '';
}

function updateFocusTimerDisplay() {
    var display = document.getElementById('focusTimerDisplay');
    if (!display) return;
    if (focusTimerSeconds <= 0) { display.textContent = ''; return; }
    var m = Math.floor(focusTimerSeconds / 60);
    var s = focusTimerSeconds % 60;
    display.textContent = '(' + m + ':' + (s < 10 ? '0' : '') + s + ')';
}

